import kfp
from kfp import dsl

def preprocess_op(data_path: str) -> dsl.ContainerOp:
    return dsl.ContainerOp(
        name='Preprocess Data',
        image='python:3.9',
        command=['python', '-c'],
        arguments=[
            'import pandas as pd; df = pd.read_csv("' + data_path + '"); df = df.dropna(); df.to_csv("/output/preprocessed.csv", index=False)'
        ],
        file_outputs={'output': '/output/preprocessed.csv'}
    )

def train_op(data_path: str) -> dsl.ContainerOp:
    return dsl.ContainerOp(
        name='Train Model',
        image='python:3.9',
        command=['python', '-c'],
        arguments=[
            'import pandas as pd; import joblib; from sklearn.ensemble import RandomForestClassifier; df = pd.read_csv("' + data_path + '"); X = df.iloc[:,:-1]; y = df.iloc[:,-1]; model = RandomForestClassifier(); model.fit(X, y); joblib.dump(model, "/output/model.joblib")'
        ],
        file_outputs={'model': '/output/model.joblib'}
    )

@dsl.pipeline(
    name='Simple Training Pipeline',
    description='A pipeline that preprocesses data and trains a model'
)
def pipeline(data_path: str = '/data/dataset.csv'):
    preprocess_task = preprocess_op(data_path)
    train_task = train_op(preprocess_task.outputs['output'])

# Compile the pipeline
kfp.compiler.Compiler().compile(pipeline, 'pipeline.yaml')

