__global__ void threshold_kernel(float* confidence_scores, float* out_masks, float threshold, int num_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        // Branchless assignment for higher warp efficiency
        out_masks[idx] = (confidence_scores[idx] >= threshold) ? 1.0f : 0.0f;
    }
}

// Host execution wrapper
void run_threshold(float* d_scores, float* d_masks, float threshold, int current_batch_size) {
    int threads = 256;
    int blocks = (current_batch_size + threads - 1) / threads;
    threshold_kernel<<<blocks, threads>>>(d_scores, d_masks, threshold, current_batch_size);
    cudaDeviceSynchronize();
}

